// useAccountStore.js
import { create } from 'zustand';

const useAccountStore = create((set) => ({
  cardArr: [],
  setCardArr: (cards) => set((state) => ({
    cardArr: [...state.cardArr, ...cards]
  })),




}));

export default useAccountStore;
